import base64, os, shutil, sys

DATA = ''

def main():
    project_root = os.getcwd()
    target = os.path.join(project_root, "src", "lexer", "gurudev_lexer.py")
    if not os.path.isdir(os.path.join(project_root, "src")):
        print("ERRO: Diretorio src/ nao encontrado.")
        print("Execute no diretorio raiz do gurudev-core.")
        sys.exit(1)
    lexer_dir = os.path.join(project_root, "src", "lexer")
    os.makedirs(lexer_dir, exist_ok=True)
    content = base64.b64decode(DATA)
    with open(target, "wb") as f:
        f.write(content)
    print(f"Arquivo corrigido: {target}")
    print(f"Tamanho: {len(content)} bytes")
    init_lexer = os.path.join(lexer_dir, "__init__.py")
    if not os.path.exists(init_lexer):
        with open(init_lexer, "w", encoding="utf-8") as f:
            f.write('from .gurudev_lexer import build_lexer, tokenize, tokens\n')
            f.write("__all__ = ['build_lexer', 'tokenize', 'tokens']\n")
        print(f"Criado: {init_lexer}")
    init_src = os.path.join(project_root, "src", "__init__.py")
    if not os.path.exists(init_src):
        with open(init_src, "w", encoding="utf-8") as f:
            f.write('')
        print(f"Criado: {init_src}")
    for d in [os.path.join(project_root, "src", "__pycache__"),
              os.path.join(lexer_dir, "__pycache__")]:
        if os.path.isdir(d):
            shutil.rmtree(d)
            print(f"Limpo: {d}")
    for fn in [os.path.join(project_root, "src", "parsetab.py"),
              os.path.join(project_root, "src", "parser.out")]:
        if os.path.exists(fn):
            os.remove(fn)
            print(f"Removido: {fn}")
    print()
    print("=" * 50)
    print("SUCESSO! Lexer corrigido.")
    print('Agora execute: python examples\\run_example.py')

if __name__ == "__main__":
    main()
